import React from 'react';
import './Section.css';
import Article from "../Article.js";
import { ArticleChoices } from "../ArticleChoices.js";

class Section extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
      this.collapse();
  }

  test(a) {
    temp_story = ArticleChoices[a].stories;
    temp_descr = ArticleChoices[a].description;
    return (
        <div className='content-holder'>
            <div id='descriptions'>
                {temp_descr.map(i => (
                    <p key={i}>{temp_descr[i]}</p>
                ))}
            </div>
            <div id='stories'>
                {temp_story.map(i => {
                    <Article index={i}/>
                })}
            </div>
        </div>


    )
  }

  render() {
    return (
      <div className='outer'>
          <div id='topBar'>
             <h2>{this.props.title}</h2>
          </div>
          {this.test(this.props.index)}
      </div>
    );
  }
}

const Portfolio = () => {
    return (
        <div id='portfolio'>
            <Section title='Reporting on UCLA student at the U.S. Capitol riots' index={0}/>
        </div>
    );
}

export default Portfolio;
